mapper.select:
SELECT r.menu_id
  FROM om_auth_group_menu_r r
 WHERE r.auth_group_cd = #{authGroupCd}
   AND r.system_main_cd = #{systemMainCd}
   AND r.system_sub_cd = #{systemSubCd}
   AND COALESCE(r.is_deleted, false) = false
 ORDER BY r.menu_id ASC

SELECT r.menu_id
  FROM om_auth_group_menu_r r
  INNER JOIN om_menu_m m
          ON m.menu_id = r.menu_id
         AND COALESCE(m.is_deleted, false) = false
         AND COALESCE(m.is_active, true) = true
         AND m.system_main_cd = #{systemMainCd}
         AND m.system_sub_cd = #{systemSubCd}
 WHERE r.auth_group_cd = #{authGroupCd}
   AND r.system_main_cd = #{systemMainCd}
   AND r.system_sub_cd = #{systemSubCd}
   AND COALESCE(r.is_deleted, false) = false
   AND COALESCE(r.can_view, false) = true
 ORDER BY r.menu_id ASC

mapper.update:
UPDATE om_auth_group_menu_r
   SET is_deleted = true
     , updated_at = CURRENT_TIMESTAMP
     , updated_by = #{userId}
 WHERE auth_group_cd = #{authGroupCd}
   AND system_main_cd = #{systemMainCd}
   AND system_sub_cd = #{systemSubCd}
   AND COALESCE(is_deleted, false) = false

UPDATE om_auth_group_menu_r
   SET is_deleted = true
     , updated_at = CURRENT_TIMESTAMP
     , updated_by = #{userId}
 WHERE auth_group_cd = #{authGroupCd}
   AND COALESCE(is_deleted, false) = false
